  {
    auth: 'admin',
    bodySchema: createContextExercisesSchema,
  },
  async ({ payload, body, user }) => {
    const { lessonId } = body

    const result = await createExercisesFromExtraction({
      payload,
      user: user!,
      lessonId,
    })

